/**
 * 📦 Stock Media Service
 * 
 * Serviço centralizado para busca de mídias stock (fotos e vídeos) de APIs externas.
 * Providers suportados: Pexels (primário), Pixabay (fallback).
 * 
 * Features:
 * - Cache in-memory com TTL configurável
 * - Fallback automático entre providers
 * - Rate limit tracking
 * - Metadados de licença/atribuição
 * - Tipos unificados para todos os providers
 * 
 * @module stock-media
 */

import { logger } from '@/lib/logger';

// ============================================================================
// TYPES
// ============================================================================

/** Tipos de mídia suportados */
export type StockMediaType = 'image' | 'video';

/** Providers de mídia stock */
export type StockProvider = 'pexels' | 'pixabay';

/** Orientação da mídia */
export type StockOrientation = 'landscape' | 'portrait' | 'square';

/** Informações de licença */
export interface StockLicense {
  type: string;
  attributionRequired: boolean;
  attributionText: string;
  detailsUrl: string;
}

/** Item de mídia stock unificado */
export interface StockMediaItem {
  id: string;
  title: string;
  type: StockMediaType;
  thumbnail: string;
  previewUrl: string;
  downloadUrl: string;
  source: StockProvider;
  author: string;
  authorUrl: string;
  sourceUrl: string;
  license: StockLicense;
  width: number;
  height: number;
  duration?: number;
  tags?: string[];
}

/** Parâmetros de busca */
export interface StockSearchParams {
  query: string;
  type?: StockMediaType | 'all';
  page?: number;
  perPage?: number;
  orientation?: StockOrientation;
  minWidth?: number;
  minHeight?: number;
  locale?: string;
}

/** Resultado de busca paginado */
export interface StockSearchResult {
  items: StockMediaItem[];
  total: number;
  page: number;
  perPage: number;
  hasMore: boolean;
  provider: StockProvider;
  query: string;
  cached: boolean;
}

/** Configuração de provider */
interface ProviderConfig {
  apiKey: string;
  enabled: boolean;
}

/** Status de rate limit */
interface RateLimitStatus {
  remaining: number;
  limit: number;
  resetAt: number;
}

// ============================================================================
// CONSTANTS
// ============================================================================

/** Duração padrão do cache em ms (5 minutos) */
const CACHE_TTL_MS = 5 * 60 * 1000;

/** Máximo de itens no cache */
const MAX_CACHE_ENTRIES = 200;

/** Per page padrão */
const DEFAULT_PER_PAGE = 20;

/** Timeout para requests em ms */
const REQUEST_TIMEOUT_MS = 10_000;

// ============================================================================
// CACHE
// ============================================================================

interface CacheEntry {
  result: StockSearchResult;
  timestamp: number;
}

const cache = new Map<string, CacheEntry>();

function getCacheKey(provider: StockProvider, params: StockSearchParams): string {
  return `${provider}:${params.query}:${params.type || 'all'}:${params.page || 1}:${params.perPage || DEFAULT_PER_PAGE}:${params.orientation || ''}`;
}

function getFromCache(key: string): StockSearchResult | null {
  const entry = cache.get(key);
  if (!entry) return null;

  if (Date.now() - entry.timestamp > CACHE_TTL_MS) {
    cache.delete(key);
    return null;
  }

  return { ...entry.result, cached: true };
}

function setInCache(key: string, result: StockSearchResult): void {
  // Evict oldest entries if cache is full
  if (cache.size >= MAX_CACHE_ENTRIES) {
    const oldestKey = cache.keys().next().value;
    if (oldestKey !== undefined) {
      cache.delete(oldestKey);
    }
  }
  cache.set(key, { result, timestamp: Date.now() });
}

/** Limpa o cache inteiro (útil para testes) */
export function clearStockMediaCache(): void {
  cache.clear();
}

/** Retorna o tamanho atual do cache */
export function getStockMediaCacheSize(): number {
  return cache.size;
}

// ============================================================================
// RATE LIMIT TRACKING
// ============================================================================

const rateLimits: Record<StockProvider, RateLimitStatus> = {
  pexels: { remaining: 200, limit: 200, resetAt: 0 },
  pixabay: { remaining: 100, limit: 100, resetAt: 0 },
};

function updateRateLimit(provider: StockProvider, headers: Headers): void {
  const remaining = headers.get('x-ratelimit-remaining');
  const limit = headers.get('x-ratelimit-limit');
  const reset = headers.get('x-ratelimit-reset');

  if (remaining !== null) {
    rateLimits[provider].remaining = parseInt(remaining, 10);
  }
  if (limit !== null) {
    rateLimits[provider].limit = parseInt(limit, 10);
  }
  if (reset !== null) {
    rateLimits[provider].resetAt = parseInt(reset, 10) * 1000;
  }
}

function isRateLimited(provider: StockProvider): boolean {
  const status = rateLimits[provider];
  if (status.remaining <= 0 && Date.now() < status.resetAt) {
    return true;
  }
  // Reset if past the reset window
  if (status.remaining <= 0 && Date.now() >= status.resetAt) {
    status.remaining = status.limit;
  }
  return false;
}

/** Retorna o status de rate limit de um provider */
export function getProviderRateLimit(provider: StockProvider): RateLimitStatus {
  return { ...rateLimits[provider] };
}

// ============================================================================
// PEXELS PROVIDER
// ============================================================================

function buildPexelsLicense(photographerUrl: string): StockLicense {
  return {
    type: 'Pexels License',
    attributionRequired: false,
    attributionText: 'Free to use. Attribution appreciated but not required.',
    detailsUrl: photographerUrl || 'https://www.pexels.com/license/',
  };
}

async function searchPexels(
  params: StockSearchParams,
  apiKey: string,
): Promise<StockSearchResult> {
  const page = params.page || 1;
  const perPage = params.perPage || DEFAULT_PER_PAGE;
  const searchType = params.type || 'all';

  const items: StockMediaItem[] = [];
  let total = 0;

  // Search images
  if (searchType === 'all' || searchType === 'image') {
    const imageParams = new URLSearchParams({
      query: params.query,
      per_page: String(perPage),
      page: String(page),
    });
    if (params.orientation) {
      imageParams.set('orientation', params.orientation);
    }
    if (params.locale) {
      imageParams.set('locale', params.locale);
    }

    const imageUrl = `https://api.pexels.com/v1/search?${imageParams.toString()}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
      const response = await fetch(imageUrl, {
        headers: { Authorization: apiKey },
        signal: controller.signal,
      });
      clearTimeout(timeoutId);

      updateRateLimit('pexels', response.headers);

      if (response.ok) {
        const data = await response.json();
        total += data.total_results || 0;

        const photos = (data.photos || []).map((p: Record<string, unknown>) => {
          const src = p.src as Record<string, string>;
          const photographerUrl = (p.photographer_url as string) || '';

          return {
            id: `pexels-${p.id}`,
            title: (p.alt as string) || `Photo by ${p.photographer}`,
            type: 'image' as const,
            thumbnail: src?.medium || src?.small || '',
            previewUrl: src?.large || src?.medium || '',
            downloadUrl: src?.original || src?.large2x || '',
            source: 'pexels' as const,
            author: (p.photographer as string) || 'Unknown',
            authorUrl: photographerUrl,
            sourceUrl: (p.url as string) || '',
            license: buildPexelsLicense(photographerUrl),
            width: (p.width as number) || 0,
            height: (p.height as number) || 0,
            tags: [],
          };
        });
        items.push(...photos);
      } else {
        logger.warn('Pexels images search failed', {
          status: response.status,
          query: params.query,
        });
      }
    } catch (error: unknown) {
      clearTimeout(timeoutId);
      if (error instanceof Error && error.name !== 'AbortError') {
        logger.error('Pexels images fetch error', error, { query: params.query });
      }
    }
  }

  // Search videos
  if (searchType === 'all' || searchType === 'video') {
    const videoParams = new URLSearchParams({
      query: params.query,
      per_page: String(perPage),
      page: String(page),
    });
    if (params.orientation) {
      videoParams.set('orientation', params.orientation);
    }

    const videoUrl = `https://api.pexels.com/videos/search?${videoParams.toString()}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
      const response = await fetch(videoUrl, {
        headers: { Authorization: apiKey },
        signal: controller.signal,
      });
      clearTimeout(timeoutId);

      updateRateLimit('pexels', response.headers);

      if (response.ok) {
        const data = await response.json();
        total += data.total_results || 0;

        const videos = (data.videos || []).map((v: Record<string, unknown>) => {
          const videoFiles = v.video_files as Array<Record<string, unknown>> | undefined;
          const bestFile = videoFiles?.[0];
          const user = v.user as Record<string, unknown> | undefined;
          const userName = (user?.name as string) || 'Unknown';
          const userUrl = (user?.url as string) || '';

          return {
            id: `pexels-v-${v.id}`,
            title: String(v.url || '').split('/').pop()?.replace(/-/g, ' ') || `Video by ${userName}`,
            type: 'video' as const,
            thumbnail: (v.image as string) || '',
            previewUrl: (bestFile?.link as string) || '',
            downloadUrl: (bestFile?.link as string) || '',
            source: 'pexels' as const,
            author: userName,
            authorUrl: userUrl,
            sourceUrl: (v.url as string) || '',
            license: buildPexelsLicense(userUrl),
            width: (v.width as number) || 0,
            height: (v.height as number) || 0,
            duration: typeof v.duration === 'number' ? v.duration : undefined,
            tags: [],
          };
        });
        items.push(...videos);
      } else {
        logger.warn('Pexels videos search failed', {
          status: response.status,
          query: params.query,
        });
      }
    } catch (error: unknown) {
      clearTimeout(timeoutId);
      if (error instanceof Error && error.name !== 'AbortError') {
        logger.error('Pexels videos fetch error', error, { query: params.query });
      }
    }
  }

  return {
    items,
    total,
    page,
    perPage,
    hasMore: items.length === perPage,
    provider: 'pexels',
    query: params.query,
    cached: false,
  };
}

// ============================================================================
// PIXABAY PROVIDER
// ============================================================================

function buildPixabayLicense(): StockLicense {
  return {
    type: 'Pixabay Content License',
    attributionRequired: false,
    attributionText: 'Free for commercial use. No attribution required.',
    detailsUrl: 'https://pixabay.com/service/license-summary/',
  };
}

async function searchPixabay(
  params: StockSearchParams,
  apiKey: string,
): Promise<StockSearchResult> {
  const page = params.page || 1;
  const perPage = params.perPage || DEFAULT_PER_PAGE;
  const searchType = params.type || 'all';

  const items: StockMediaItem[] = [];
  let total = 0;

  // Search images
  if (searchType === 'all' || searchType === 'image') {
    const imageParams = new URLSearchParams({
      key: apiKey,
      q: params.query,
      per_page: String(Math.min(perPage, 200)),
      page: String(page),
      safesearch: 'true',
      image_type: 'photo',
    });
    if (params.orientation) {
      imageParams.set('orientation', params.orientation === 'square' ? 'all' : params.orientation);
    }
    if (params.minWidth) {
      imageParams.set('min_width', String(params.minWidth));
    }
    if (params.minHeight) {
      imageParams.set('min_height', String(params.minHeight));
    }
    if (params.locale) {
      imageParams.set('lang', mapLocaleToPixabay(params.locale));
    }

    const imageUrl = `https://pixabay.com/api/?${imageParams.toString()}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
      const response = await fetch(imageUrl, { signal: controller.signal });
      clearTimeout(timeoutId);

      updateRateLimit('pixabay', response.headers);

      if (response.ok) {
        const data = await response.json();
        total += data.totalHits || 0;

        const photos = (data.hits || []).map((hit: Record<string, unknown>) => ({
          id: `pixabay-${hit.id}`,
          title: (hit.tags as string)?.split(',')[0]?.trim() || `Pixabay ${hit.id}`,
          type: 'image' as const,
          thumbnail: (hit.webformatURL as string) || (hit.previewURL as string) || '',
          previewUrl: (hit.webformatURL as string) || '',
          downloadUrl: (hit.largeImageURL as string) || (hit.fullHDURL as string) || (hit.webformatURL as string) || '',
          source: 'pixabay' as const,
          author: (hit.user as string) || 'Unknown',
          authorUrl: `https://pixabay.com/users/${hit.user}-${hit.user_id}/`,
          sourceUrl: (hit.pageURL as string) || '',
          license: buildPixabayLicense(),
          width: (hit.imageWidth as number) || 0,
          height: (hit.imageHeight as number) || 0,
          tags: ((hit.tags as string) || '').split(',').map((t: string) => t.trim()).filter(Boolean),
        }));
        items.push(...photos);
      } else {
        logger.warn('Pixabay images search failed', {
          status: response.status,
          query: params.query,
        });
      }
    } catch (error: unknown) {
      clearTimeout(timeoutId);
      if (error instanceof Error && error.name !== 'AbortError') {
        logger.error('Pixabay images fetch error', error, { query: params.query });
      }
    }
  }

  // Search videos
  if (searchType === 'all' || searchType === 'video') {
    const videoParams = new URLSearchParams({
      key: apiKey,
      q: params.query,
      per_page: String(Math.min(perPage, 200)),
      page: String(page),
      safesearch: 'true',
    });

    const videoUrl = `https://pixabay.com/api/videos/?${videoParams.toString()}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
      const response = await fetch(videoUrl, { signal: controller.signal });
      clearTimeout(timeoutId);

      updateRateLimit('pixabay', response.headers);

      if (response.ok) {
        const data = await response.json();
        total += data.totalHits || 0;

        const videos = (data.hits || []).map((hit: Record<string, unknown>) => {
          const videosData = hit.videos as Record<string, Record<string, unknown>> | undefined;
          const medium = videosData?.medium;
          const large = videosData?.large;
          const best = large || medium;

          return {
            id: `pixabay-v-${hit.id}`,
            title: (hit.tags as string)?.split(',')[0]?.trim() || `Pixabay Video ${hit.id}`,
            type: 'video' as const,
            thumbnail: (hit.picture_id as string)
              ? `https://i.vimeocdn.com/video/${hit.picture_id}_640x360.jpg`
              : '',
            previewUrl: (best?.url as string) || '',
            downloadUrl: (best?.url as string) || '',
            source: 'pixabay' as const,
            author: (hit.user as string) || 'Unknown',
            authorUrl: `https://pixabay.com/users/${hit.user}-${hit.user_id}/`,
            sourceUrl: (hit.pageURL as string) || '',
            license: buildPixabayLicense(),
            width: (best?.width as number) || 0,
            height: (best?.height as number) || 0,
            duration: typeof hit.duration === 'number' ? hit.duration : undefined,
            tags: ((hit.tags as string) || '').split(',').map((t: string) => t.trim()).filter(Boolean),
          };
        });
        items.push(...videos);
      } else {
        logger.warn('Pixabay videos search failed', {
          status: response.status,
          query: params.query,
        });
      }
    } catch (error: unknown) {
      clearTimeout(timeoutId);
      if (error instanceof Error && error.name !== 'AbortError') {
        logger.error('Pixabay videos fetch error', error, { query: params.query });
      }
    }
  }

  return {
    items,
    total,
    page,
    perPage,
    hasMore: items.length === perPage,
    provider: 'pixabay',
    query: params.query,
    cached: false,
  };
}

/** Mapeia locale para código de idioma Pixabay */
function mapLocaleToPixabay(locale: string): string {
  const map: Record<string, string> = {
    'pt-BR': 'pt',
    'pt': 'pt',
    'en-US': 'en',
    'en': 'en',
    'es': 'es',
    'fr': 'fr',
    'de': 'de',
    'it': 'it',
    'ja': 'ja',
    'ko': 'ko',
    'zh': 'zh',
  };
  return map[locale] || 'en';
}

// ============================================================================
// MAIN SERVICE
// ============================================================================

/** Configuração do serviço obtida via variáveis de ambiente */
function getProviderConfigs(): Record<StockProvider, ProviderConfig> {
  return {
    pexels: {
      apiKey: process.env.PEXELS_API_KEY || '',
      enabled: Boolean(process.env.PEXELS_API_KEY),
    },
    pixabay: {
      apiKey: process.env.PIXABAY_API_KEY || '',
      enabled: Boolean(process.env.PIXABAY_API_KEY),
    },
  };
}

/** Retorna quais providers estão configurados */
export function getAvailableProviders(): StockProvider[] {
  const configs = getProviderConfigs();
  return (Object.entries(configs) as Array<[StockProvider, ProviderConfig]>)
    .filter(([, config]) => config.enabled)
    .map(([provider]) => provider);
}

/**
 * Busca mídias stock de forma unificada.
 * - Tenta o provider principal (Pexels)
 * - Se falhar ou estiver rate-limited, usa fallback (Pixabay)
 * - Retorna resultados cacheados quando disponíveis
 */
export async function searchStockMedia(
  params: StockSearchParams,
  preferredProvider?: StockProvider,
): Promise<StockSearchResult> {
  const configs = getProviderConfigs();

  // Determine provider order
  const providerOrder: StockProvider[] = preferredProvider
    ? [preferredProvider, ...(['pexels', 'pixabay'] as StockProvider[]).filter(p => p !== preferredProvider)]
    : ['pexels', 'pixabay'];

  // Try each provider in order
  for (const provider of providerOrder) {
    const config = configs[provider];
    if (!config.enabled) continue;
    if (isRateLimited(provider)) {
      logger.warn(`Stock media provider ${provider} is rate-limited, trying next`, {
        provider,
        resetAt: rateLimits[provider].resetAt,
      });
      continue;
    }

    // Check cache
    const cacheKey = getCacheKey(provider, params);
    const cached = getFromCache(cacheKey);
    if (cached) {
      return cached;
    }

    try {
      let result: StockSearchResult;

      if (provider === 'pexels') {
        result = await searchPexels(params, config.apiKey);
      } else {
        result = await searchPixabay(params, config.apiKey);
      }

      // Cache successful results
      if (result.items.length > 0) {
        setInCache(cacheKey, result);
      }

      return result;
    } catch (error: unknown) {
      logger.error(`Stock media search failed for ${provider}`, error instanceof Error ? error : new Error(String(error)), {
        provider,
        query: params.query,
      });
      // Continue to next provider
    }
  }

  // No providers available
  return {
    items: [],
    total: 0,
    page: params.page || 1,
    perPage: params.perPage || DEFAULT_PER_PAGE,
    hasMore: false,
    provider: providerOrder[0] || 'pexels',
    query: params.query,
    cached: false,
  };
}

/**
 * Busca mídias de TODOS os providers habilitados e combina resultados.
 * Útil para maximizar a variedade de resultados.
 */
export async function searchAllProviders(
  params: StockSearchParams,
): Promise<StockSearchResult> {
  const configs = getProviderConfigs();
  const enabledProviders = (Object.entries(configs) as Array<[StockProvider, ProviderConfig]>)
    .filter(([, config]) => config.enabled)
    .filter(([provider]) => !isRateLimited(provider))
    .map(([provider]) => provider);

  if (enabledProviders.length === 0) {
    return {
      items: [],
      total: 0,
      page: params.page || 1,
      perPage: params.perPage || DEFAULT_PER_PAGE,
      hasMore: false,
      provider: 'pexels',
      query: params.query,
      cached: false,
    };
  }

  // Fetch from all providers in parallel
  const promises = enabledProviders.map(async (provider) => {
    const cacheKey = getCacheKey(provider, params);
    const cached = getFromCache(cacheKey);
    if (cached) return cached;

    try {
      const result = provider === 'pexels'
        ? await searchPexels(params, configs[provider].apiKey)
        : await searchPixabay(params, configs[provider].apiKey);

      if (result.items.length > 0) {
        setInCache(cacheKey, result);
      }
      return result;
    } catch {
      return null;
    }
  });

  const results = await Promise.all(promises);
  const validResults = results.filter((r): r is StockSearchResult => r !== null);

  // Combine and interleave results
  const allItems: StockMediaItem[] = [];
  const maxLen = Math.max(...validResults.map(r => r.items.length));
  for (let i = 0; i < maxLen; i++) {
    for (const result of validResults) {
      if (i < result.items.length) {
        allItems.push(result.items[i]);
      }
    }
  }

  return {
    items: allItems,
    total: validResults.reduce((sum, r) => sum + r.total, 0),
    page: params.page || 1,
    perPage: params.perPage || DEFAULT_PER_PAGE,
    hasMore: validResults.some(r => r.hasMore),
    provider: enabledProviders[0],
    query: params.query,
    cached: validResults.every(r => r.cached),
  };
}

/** Formata a atribuição de uma mídia para exibição */
export function formatAttribution(item: StockMediaItem): string {
  if (item.source === 'pexels') {
    return `Photo by ${item.author} on Pexels`;
  }
  if (item.source === 'pixabay') {
    return `${item.author} on Pixabay`;
  }
  return item.author;
}

/** Retorna o link da página do provider */
export function getProviderUrl(provider: StockProvider): string {
  const urls: Record<StockProvider, string> = {
    pexels: 'https://www.pexels.com',
    pixabay: 'https://pixabay.com',
  };
  return urls[provider];
}

/** Converte StockMediaItem para formato do canvas */
export function stockMediaToCanvasData(item: StockMediaItem): {
  type: 'image' | 'video';
  name: string;
  url: string;
  width: number;
  height: number;
  attribution: string;
  source: StockProvider;
  sourceUrl: string;
} {
  return {
    type: item.type,
    name: item.title,
    url: item.downloadUrl || item.previewUrl,
    width: item.width || 1920,
    height: item.height || 1080,
    attribution: formatAttribution(item),
    source: item.source,
    sourceUrl: item.sourceUrl,
  };
}

